var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"내 고향에 버려진 집이 한 채 있었다.","JPN":"我が故郷には一軒の捨てられた家があった。","ENG":"There used to be an abandoned house in my hometown.","TWN":"在我的故鄉有一間廢棄的房屋。","THA":"ที่บ้านเกิดฉันเคยมีบ้านร้างอยู่","VTN":"Quê hương tôi từng có một ngôi nhà bỏ hoang.","SCN":"在我的故乡有一处遗弃的房子。","DEU":"In meiner Heimat gab es ein verlassenes Haus.","FRA":"Dans mon village natal, il y avait une maison abandonnée."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"마을 어른들은 부정이 탔다면서 그 집을 허물지도, 새 주민이 오지도 못하게 했다.","JPN":"村の大人たちは縁起が悪いと言って、その家を取り壊すことも、新しい住人が来ることも阻止した。","ENG":"The village elders claimed it was cursed and refused to demolish it or allow new residents to move in.","TWN":"村裡的大人們嫌它晦氣，於是沒有拆除，也沒有新的人入住。","THA":"คนเฒ่าคนแก่ในหมู่บ้านบอกว่ามันต้องคำสาป และไม่ยอมทำลายหรือให้มีใครย้ายเข้าไปอยู่","VTN":"Các già làng cho rằng nó đã bị nguyền rủa và từ chối phá dỡ nó cũng như không cho phép những cư dân mới chuyển đến.","SCN":"村里的大人们说那个房子受到了诅咒，不让拆除也不让新的人入住。","DEU":"Die Dorfältesten haben verhindert, dass dieses Haus abgerissen wird oder dass jemand dort einzieht, da es verflucht sei.","FRA":"Les aînés du village ont toujours fait en sorte que personne ne s'y installe, et ils ont toujours refusé de la détruire."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"그 집은 어른들의 두려움이 고인 우물이오, 나 같은 철부지들에겐 탐험심을 부추기는 미답지였다.","JPN":"あの家は村人たちの恐怖の念が溜まった井戸であり、\\n私のような世間知らずにとっては、冒険心を掻き立てる未踏の地であった。","ENG":"The house drew fear from the adults, but it was an unexplored place ripe with adventure for a curious young kid like me.","TWN":"大人們對那間房屋充滿恐懼，如同一口井深不見底。但對我這種不知天高地厚的小鬼，卻埋下好奇心。","THA":"บ้านหลังนั้นทำให้พวกผู้ใหญ่หวาดกลัว แต่มันคือที่ที่ยังไม่มีใครไปสำรวจ เต็มไปด้วยการผจญภัยสำหรับเด็กขี้สงสัยอย่างฉัน","VTN":"Ngôi nhà đó khiến những người trưởng thành sợ hãi, nhưng nó là một nơi đầy bí ẩn, giống như một quả táo thơm ngon đối với một đứa trẻ tò mò như tôi.","SCN":"虽然那个房子对大人们来说就像是恐惧的深渊，但对我这样的小孩子却是未知的探险圣地。","DEU":"Dieses Haus sei ein Brunnen, der mit den Ängsten der Erwachsenen gefüllt ist, und zugleich ein unerkundetes Land, das in einem Kind wie mir die Abenteuerlust erweckt hatte.","FRA":"Cette maison était une source de terreur pour eux mais moi elle était synonyme d'inconnu, d'aventure."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"골목을 주름잡던 무리는 때때로 담력을 자랑하느라고 으레 그 집으로 찾아갔다.","JPN":"村で幅を利かせていた連中は、よく肝試しにその家を訪ねていた。","ENG":"Many groups of kids came to the house to show off their bravery.","TWN":"村裡的小孩偶爾去那間房屋探險，證明自己的膽量。","THA":"เด็กหลายกลุ่มต่างไปที่บ้านหลังนั้นเพื่ออวดว่าตัวเองกล้ากัน","VTN":"Rất nhiều nhóm trẻ đã đến đó để thể hiện sự dũng cảm của mình.","SCN":"在小巷中横冲直撞的孩子们为了证明自己的勇气，决定去那个房子试炼胆量。","DEU":"Für viele war es daher eine Mutprobe, dieses Haus zu besuchen.","FRA":"Ceux qui régnaient dans la rue s'y rendaient toujours pour prouver leur courage."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"subtitle","speaker":null,"text":{"KOREA":"무리에 속한 나는 그 집에 사람 잡아먹는 할아버지나 외눈박이 괴물이 없는 줄 이미 알고 있었다.","JPN":"連中の一員だった私は、その家には人食いジジイも隻眼の怪物もいないことをすでに知っていた。","ENG":"As a member of this group, I was already aware that there was no old man who ate children or a one-eyed monster living inside.","TWN":"而我也是其中之一，但我早就知道，那裡面沒有會吃人的老爺爺，或是獨眼怪物。","THA":"ตอนนั้นฉันเองที่ก็อยู่ในกลุ่มเด็กพวกนั้นรู้อยู่แล้วว่า บ้านนั้นไม่ได้มีคนแก่กินเด็กหรือสัตว์ประหลาดตาเดียวอาศัยอยู่หรอก","VTN":"Là một thành viên của nhóm này, tôi đã nhận thấy rằng không có ông già ăn thịt trẻ em hay một con quái vật một mắt nào sống bên trong.","SCN":"虽然我也和孩子们一起去探险，但我早就知道那个房子里根本没有会吃人的老爷爷和独眼龙怪物。","DEU":"Unter diesen Leuten war auch ich. Aber ich wusste schon, dass dort weder ein alter Kannibale noch ein Zyklop zu Hause war.","FRA":"J'étais avec eux, alors je savais bien qu'il n'y avait ni vieillards, ni cyclopes dévoreurs d'hommes dans cette maison."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"subtitle","speaker":null,"text":{"KOREA":"하지만 그 날은 마당에 들어섰을 때의 공기부터 별났다.","ENG":"But as soon as we stepped into the yard that day, everything felt different.","TWN":"但那天，當我踏進大門時，空氣中就瀰漫著一股不尋常的味道。","THA":"แต่ทันทีที่เราเหยียบเข้าสวนไปในวันนั้น ทุกอย่างก็ดูแปลกไป","VTN":"Nhưng ngay khi bước chân vào sân của ngôi nhà ấy ngày hôm đó, mọi thứ đã khác hẳn.","SCN":"不过那天走进院子时，呼吸到的空气感觉和以往不同。","DEU":"Aber an jenem Tage habe ich im Vorhof eine seltsame Aura wahrgenommen.","FRA":"Mais ce jour-là, en pénétrant dans la cour, j'ai senti que quelque chose était différent."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"subtitle","speaker":null,"text":{"KOREA":"어둡고 곰팡이 슨 방구석에, 우두커니 서 있던 형체.","JPN":"暗くてかび臭い部屋の隅に、ぼんやりと立っていたシルエット。","ENG":"In the dark, moldy corner of the room, a figure stood.","TWN":"我看到在陰暗發霉的角落，有個東西直挺挺地站在那。","THA":"ในมุมมืดมิดที่มีราขึ้นของห้องนั้น มีร่างหนึ่งยืนอยู่","VTN":"Trong góc phòng đen tối, ẩm mốc, một bóng hình đang đứng.","SCN":"伫立在黑暗潮湿角落中的孤独的形体。","DEU":"Eine aufrecht stehende Gestalt in einem dunklen mit Schimmel befallenen Zimmer.","FRA":"Une silhouette se tenait dans un coin sombre."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"subtitle","speaker":null,"text":{"KOREA":"짐승처럼 으르렁거리며, 깨진 바위 같은 앞발을 경련하던 존재.","ENG":"The beast-like creature growled and twitched its rock-like forefeet.","TWN":"那個東西如野獸般嘶吼，如同碎石般的前腳抽搐著。","THA":"เจ้าตัวที่เหมือนสัตว์ร้ายนั่นส่งเสียงคำรามพลางเกร็งเท้าหน้าที่ดูเหมือนหินจนกระตุก","VTN":"Sinh vật giống quái vật ấy gầm gừ và co giật chi trước giống như đá của nó.","SCN":"像野兽一样咆哮，有岩石般坚硬前肢的存在。","DEU":"Es hat geknurrt wie ein Biest und seine Tatzen, die Steinklumpen ähnelten, haben gezittert.","FRA":"Une créature qui grognait comme une bête sauvage avec des pattes serties d'éclats rocheux."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"subtitle","speaker":null,"text":{"KOREA":"기억하고 있다.","ENG":"I remember it all too well.","TWN":"我記得很清楚。","THA":"ฉันจำได้หมดไม่มีลืมเลย","VTN":"Tôi vẫn nhớ nó rất rõ.","SCN":"我一直都记得。","DEU":"Ich erinnere mich.","FRA":"Je m'en souviens comme si c'était hier."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"subtitle","speaker":null,"text":{"KOREA":"이제는 없는 내 고향에, 버려진 집이 한 채 있었다.","ENG":"In what was once my hometown, there was an abandoned house.","TWN":"在現在已不復在的故鄉裡，有間廢物的房屋。","THA":"ในที่ที่ครั้งหนึ่งเคยเป็นบ้านเกิดฉันนั้น มีบ้านร้างหลังหนึ่งอยู่","VTN":"Ở nơi từng là quê hương của tôi, có một ngôi nhà bỏ hoang.","SCN":"现在已经消失的故乡，有一处遗弃的房子。","DEU":"In meiner Heimat, die nicht mehr existiert, gab es ein verlassenes Haus.","FRA":"Cette maison abandonnée, dans ce village qui n'est plus..."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"……지아야, 보이니?","JPN":"……ユイ、見えるか？","ENG":"Jia... Do you see it?","TWN":"……小佳，你有看到嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"인간은…… 이렇게 쉽게 상처 입는 나약한 종이란다.","JPN":"人間は……いとも簡単に傷ついてしまう、弱い生き物だ。","ENG":"Us humans... We are fragile beings.","TWN":"人類……就是如此軟弱無能的族類。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"상처 입기 두려운 나머지, 자신과 다른 존재를 구별하고 솎아내려 하지.","JPN":"傷つくことを恐れるあまり、自分とは異なる存在を区別し、排除しようとする。","ENG":"For fear of getting hurt, we try to differentiate ourselves from others unlike us.","TWN":"所以害怕受傷之餘，還會排擠和自己不同的種類。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"이 할애비는, 지아가 그런 사람들을 도와 주면 좋겠구나.","JPN":"おじいちゃんは、お前にそんな人たちを助けてほしいんだ。","ENG":"Your grandpa wishes... that you help these people, Jia.","TWN":"爺爺希望小佳可以幫助這樣的人。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"그러니 <color=#ffd34c>더 나은 세상을 위해</color>…….","JPN":"だから、<color=#ffd34c>より良い世界のために</color>……","ENG":"Therefore, <color=#ffd34c>for a better world</color>...","TWN":"所以，<color=#ffd34c>為了更好的未來</color>……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"……전부 잊어 버려라.","JPN":"……すべて忘れなさい。","ENG":"...forget everything.","TWN":"……這些事你全都忘了吧"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"subtitle","speaker":null,"text":{"KOREA":"09:16 ARC-KP1\\n알파트릭스 이노베이션\\n<color=#ff3636>사건 발생</color> 후 9시간 경과","JPN":"09:16 ARC-KP1\\nアルファトリックス・イノベーション\\n<color=#ff3636>事件発生</color>から9時間経過","ENG":"[[","TWN":"09:16 ARC-KP1\\n阿爾法崔克斯改革\\n<color=#ff3636>事件發生</color>後經過9小時","THA":"09.16 น. ARC-KP1\\nอัลฟาทริกซ์ อินโนเวชั่น\\n9 ชั่วโมงหลังจาก<color=#ff3636>เกิดเหตุ</color>","VTN":"09:16 ARC-KP1\\nCải Cách Alphatrix \\n9 giờ sau <color=#ff3636> Sự Cố</color>","SCN":"09:16 ARC-KP1\\n阿尔法崔克斯改革\\n<color=#ff3636>事件发生</color>后，经过9小时","DEU":"[[","FRA":"09h16 ARC-KP1\\nAlphatrix Innovation\\n9 heures après l'<color=#ff3636>incident</color>"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};